'use client';

import { useState, useEffect } from 'react';
import { Certificado, Curso } from '@/types/certificate';

interface Props { cert: Certificado; onClose: () => void; }

// JPG de fundo embutido em base64 para evitar problemas CORS no html2canvas
const FUNDO_JPG = 'data:image/jpeg;base64,';

export default function CertificadoPreview({ cert, onClose }: Props) {
  const [exporting, setExporting] = useState(false);
  const [curso, setCurso]         = useState<Curso | null>(null);
  const [view, setView]           = useState<'frente' | 'verso'>('frente');

  const B = '#1a2f6e';

  const formatDate = (d: string) =>
    new Date(d).toLocaleDateString('pt-PT', { day: '2-digit', month: 'long', year: 'numeric' });

  useEffect(() => {
    fetch('/api/cursos')
      .then(r => r.json())
      .then((cursos: Curso[]) => {
        const match = cursos.find(c =>
          c.nome.toLowerCase() === cert.curso.toLowerCase() || c.id === cert.cursoId
        );
        if (match) setCurso(match);
      })
      .catch(() => {});
  }, [cert.curso, cert.cursoId]);

  // ── Exportar PDF directamente com jsPDF (sem html2canvas na frente) ──
  const exportPDF = async () => {
    setExporting(true);
    try {
      const { jsPDF } = await import('jspdf');
      const pdf = new jsPDF({ orientation: 'landscape', unit: 'mm', format: 'a4' });
      const W = pdf.internal.pageSize.getWidth();  // 297mm
      const H = pdf.internal.pageSize.getHeight(); // 210mm

      // ── PÁGINA 1: FRENTE ──────────────────────────────────────────────
      // 1. Fundo JPG (tamanho A4 completo)
      pdf.addImage(FUNDO_JPG, 'JPEG', 0, 0, W, H);

      // 2. Nome do curso (top ~35% = 73.5mm, centrado)
      pdf.setFont('helvetica', 'bold');
      pdf.setFontSize(14);
      pdf.setTextColor(26, 47, 110); // #1a2f6e
      const cursoLines = pdf.splitTextToSize(cert.curso.toUpperCase(), 180);
      pdf.text(cursoLines, W / 2, H * 0.355, { align: 'center' });

      // 3. Nome do formando (top ~48% = 100.8mm, cursivo simulado com itálico)
      pdf.setFont('times', 'italic');
      pdf.setFontSize(28);
      pdf.setTextColor(26, 47, 110);
      pdf.text(cert.nomeFormando, W / 2, H * 0.515, { align: 'center' });

      // 4. QR Code (top ~72%, left ~20.5%)
      if (cert.qrCodeUrl) {
        const qrX = W * 0.205;
        const qrY = H * 0.72;
        const qrSize = W * 0.095; // ~28mm
        pdf.addImage(cert.qrCodeUrl, 'PNG', qrX, qrY, qrSize, qrSize);

        // Número do certificado por baixo do QR
        pdf.setFont('courier', 'normal');
        pdf.setFontSize(5.5);
        pdf.setTextColor(26, 47, 110);
        pdf.text(cert.numeroCertificado || '', qrX + qrSize / 2, qrY + qrSize + 3, { align: 'center' });
      }

      // ── PÁGINA 2: VERSO (se tiver conteúdo programático) ─────────────
      if (curso?.conteudoProgramatico) {
        pdf.addPage();

        // Fundo branco simples — sem bordas nem linhas
        pdf.setFillColor(255, 255, 255);
        pdf.rect(0, 0, W, H, 'F');

        // Cabeçalho do verso
        pdf.setFont('helvetica', 'bold');
        pdf.setFontSize(12);
        pdf.setTextColor(26, 47, 110);
        pdf.text('CONTEÚDO PROGRAMÁTICO', W / 2, 18, { align: 'center' });

        pdf.setFont('helvetica', 'normal');
        pdf.setFontSize(8);
        pdf.setTextColor(90, 106, 144);
        pdf.text(`${cert.curso} · ${cert.duracao || curso.duracaoPadrao || ''}`, W / 2, 25, { align: 'center' });

        // Dividir conteúdo em 2 colunas — centradas com margens iguais
        const lines = curso.conteudoProgramatico.split('\n');
        const mid = Math.ceil(lines.length / 2);
        const col1Lines = lines.slice(0, mid);
        const col2Lines = lines.slice(mid);

        const margin = 20;          // margem exterior
        const gap    = 10;          // espaço entre colunas
        const colW   = (W - margin * 2 - gap) / 2;
        const col1X  = margin;
        const col2X  = margin + colW + gap;
        let yPos = 34;

        const colCenterX = (startX: number) => startX + colW / 2;

        const renderColumn = (colLines: string[], startX: number) => {
          let y = yPos;
          for (const line of colLines) {
            const trimmed = line.trim();

            // Linha vazia — espaço
            if (!trimmed) { y += 3; continue; }

            const isMod = trimmed.startsWith('Módulo') || trimmed.startsWith('Modulo') || trimmed.startsWith('MÓDULO');

            if (isMod) {
              // Espaço generoso antes do Módulo
              y += 7;
              pdf.setFont('helvetica', 'bold');
              pdf.setFontSize(10);
              pdf.setTextColor(26, 47, 110);
              const wrapped = pdf.splitTextToSize(trimmed, colW - 2);
              // Centrado na coluna
              wrapped.forEach((wline: string) => {
                pdf.text(wline, colCenterX(startX), y, { align: 'center' });
                y += 6;
              });
              y += 1;
            } else {
              // Tópicos — centrados, tamanho maior
              pdf.setFont('helvetica', 'normal');
              pdf.setFontSize(8.5);
              pdf.setTextColor(45, 58, 96);
              // Remover bullet para centrar limpo
              const cleanLine = trimmed.startsWith('•') ? trimmed.substring(1).trim() : trimmed;
              const wrapped = pdf.splitTextToSize(cleanLine, colW - 4);
              wrapped.forEach((wline: string) => {
                pdf.text(wline, colCenterX(startX), y, { align: 'center' });
                y += 5;
              });
              y += 0.5;
            }

            if (y > H - 14) break;
          }
        };

        renderColumn(col1Lines, col1X);
        renderColumn(col2Lines, col2X);

        // Rodapé simples sem linhas
        pdf.setFont('courier', 'normal');
        pdf.setFontSize(5.5);
        pdf.setTextColor(180, 180, 190);
        pdf.text(cert.numeroCertificado || '', 12, H - 6);
        pdf.text(`Emitido em ${formatDate(cert.dataEmissao)} · Instituto Nacional de Qualificações (INQ)`, W / 2, H - 6, { align: 'center' });
      }

      pdf.save(`Certificado_${cert.numeroCertificado}_${cert.nomeFormando.replace(/\s+/g, '_')}.pdf`);
    } catch (err) {
      console.error('Erro PDF:', err);
      alert('Erro ao gerar PDF: ' + (err instanceof Error ? err.message : String(err)));
    } finally { setExporting(false); }
  };

  // Dividir conteúdo para preview do verso
  const splitColumns = (text: string) => {
    const lines = text.split('\n').filter(l => l.trim());
    const mid = Math.ceil(lines.length / 2);
    return [lines.slice(0, mid), lines.slice(mid)];
  };
  const [col1, col2] = splitColumns(curso?.conteudoProgramatico || '');

  const renderLine = (line: string, i: number) => {
    const t = line.trim();
    const isMod    = !t.startsWith('•') && t.length > 3;
    const isBullet = t.startsWith('•');
    return (
      <p key={i} style={{
        margin: isMod ? '8px 0 3px' : '1px 0',
        fontSize: isMod ? 'clamp(7px,0.85vw,10px)' : 'clamp(6px,0.75vw,9px)',
        fontWeight: isMod ? 700 : 400,
        color: isMod ? B : '#2d3a60',
        paddingLeft: isBullet ? 8 : 0,
        lineHeight: 1.5,
        fontFamily: isMod ? 'Georgia, serif' : 'Arial, sans-serif',
        borderBottom: isMod ? `1px solid ${B}22` : 'none',
        paddingBottom: isMod ? 2 : 0,
      }}>{t}</p>
    );
  };

  return (
    <div className="fixed inset-0 bg-black/85 backdrop-blur-sm z-50 flex items-start justify-center p-4 overflow-y-auto" onClick={onClose}>
      <div className="w-full max-w-5xl my-6" onClick={e => e.stopPropagation()}>

        {/* Toolbar */}
        <div className="flex items-center justify-between mb-4">
          <button onClick={onClose} className="text-slate-400 hover:text-white text-sm transition">← Fechar</button>
          <div className="flex items-center gap-3">
            <div className="flex gap-1 bg-slate-800 rounded-lg p-1">
              {(['frente', 'verso'] as const).map(v => (
                <button key={v} onClick={() => setView(v)}
                  className={`px-3 py-1.5 rounded-md text-xs font-medium transition-all ${view === v ? 'bg-blue-600 text-white' : 'text-slate-400 hover:text-white'}`}>
                  {v === 'frente' ? '🎓 Frente' : '📋 Verso'}
                </button>
              ))}
            </div>
            <a href={`/verificar/${cert.id}`} target="_blank" rel="noopener noreferrer"
              className="px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg text-sm transition">🔗 Verificar</a>
            <button onClick={exportPDF} disabled={exporting}
              className="px-4 py-2 bg-blue-600 hover:bg-blue-500 disabled:opacity-60 text-white rounded-lg text-sm font-bold transition flex items-center gap-2">
              {exporting
                ? <><span className="w-3.5 h-3.5 border-2 border-white/30 border-t-white rounded-full animate-spin"/>A gerar PDF...</>
                : `⬇ PDF${curso?.conteudoProgramatico ? ' (2 págs)' : ''}`}
            </button>
          </div>
        </div>

        {/* FRENTE — pré-visualização */}
        {view === 'frente' && (
          <div style={{
            position: 'relative', width: '100%', aspectRatio: '2000 / 1414',
            backgroundImage: `url(${FUNDO_JPG})`,
            backgroundSize: '100% 100%', overflow: 'hidden',
            boxShadow: '0 25px 70px rgba(0,0,0,0.5)',
          }}>
            {/* Curso */}
            <div style={{ position: 'absolute', top: '35%', left: '15%', right: '15%', textAlign: 'center' }}>
              <p style={{ margin: 0, color: B, fontSize: 'clamp(10px,1.6vw,20px)', fontWeight: 700, letterSpacing: '0.1em', textTransform: 'uppercase', fontFamily: 'Georgia, serif', lineHeight: 1.3 }}>
                {cert.curso.toUpperCase()}
              </p>
            </div>
            {/* Nome */}
            <div style={{ position: 'absolute', top: '51%', left: '20%', right: '20%', textAlign: 'center' }}>
              <p style={{ margin: 0, color: B, fontSize: 'clamp(16px,2.8vw,38px)', fontFamily: "'Brush Script MT', 'Segoe Script', cursive", fontWeight: 400, lineHeight: 1.2, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                {cert.nomeFormando}
              </p>
            </div>
            {/* QR Code */}
            <div style={{ position: 'absolute', top: '72%', left: '20.5%', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2 }}>
              {cert.qrCodeUrl && <img src={cert.qrCodeUrl} alt="QR" style={{ width: 'clamp(52px,8vw,90px)', height: 'clamp(52px,8vw,90px)' }} />}
              <p style={{ margin: 0, color: B, fontSize: 'clamp(4px,0.6vw,7px)', fontFamily: 'monospace', textAlign: 'center' }}>{cert.numeroCertificado}</p>
            </div>
          </div>
        )}

        {/* VERSO — pré-visualização */}
        {view === 'verso' && (
          <div style={{
            width: '100%', aspectRatio: '297/210',
            background: 'linear-gradient(160deg, #f8f9ff 0%, #ffffff 60%, #f4f6ff 100%)',
            boxShadow: '0 25px 70px rgba(0,0,0,0.5)', overflow: 'hidden', position: 'relative',
          }}>
            <div style={{ position: 'absolute', inset: 10, border: `2.5px solid ${B}`, pointerEvents: 'none', zIndex: 2 }}/>
            <div style={{ position: 'absolute', inset: 14, border: `1px solid ${B}44`, pointerEvents: 'none', zIndex: 2 }}/>
            <div style={{ position: 'relative', zIndex: 3, padding: '4% 5% 4%', height: '100%', display: 'flex', flexDirection: 'column' }}>
              <div style={{ textAlign: 'center', marginBottom: '1.5%', borderBottom: `2px solid ${B}`, paddingBottom: '1.5%' }}>
                <p style={{ margin: 0, color: B, fontSize: 'clamp(8px,1.1vw,13px)', fontWeight: 700, letterSpacing: '0.15em', textTransform: 'uppercase', fontFamily: 'Georgia, serif' }}>Conteúdo Programático</p>
                <p style={{ margin: '3px 0 0', color: B, fontSize: 'clamp(7px,0.85vw,10px)', opacity: 0.75 }}>{cert.curso} · {cert.duracao || curso?.duracaoPadrao || ''}</p>
              </div>
              {curso?.conteudoProgramatico ? (
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '0 4%', flex: 1, overflow: 'hidden' }}>
                  <div style={{ borderRight: `1px solid ${B}22`, paddingRight: '3%', overflow: 'hidden' }}>{col1.map((l, i) => renderLine(l, i))}</div>
                  <div style={{ overflow: 'hidden' }}>{col2.map((l, i) => renderLine(l, i + col1.length))}</div>
                </div>
              ) : (
                <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <p style={{ color: '#94a3b8', fontSize: 13 }}>Sem conteúdo programático definido.</p>
                </div>
              )}
              <div style={{ borderTop: `1px solid ${B}33`, paddingTop: '1.5%', marginTop: '2%', display: 'flex', justifyContent: 'space-between' }}>
                <p style={{ margin: 0, color: B, fontSize: 'clamp(6px,0.7vw,8px)', fontFamily: 'monospace', opacity: 0.6 }}>{cert.numeroCertificado}</p>
                <p style={{ margin: 0, color: '#64748b', fontSize: 'clamp(6px,0.7vw,8px)' }}>Emitido em {formatDate(cert.dataEmissao)} · Instituto Nacional de Qualificações (INQ)</p>
              </div>
            </div>
          </div>
        )}

        <div className="mt-3 flex items-center justify-between text-xs text-slate-600 px-1">
          <span>Nº {cert.numeroCertificado}</span>
          <span>{formatDate(cert.dataEmissao)}</span>
          <span>ID: {(cert.id as string)?.substring(0, 8)}...</span>
        </div>
      </div>
    </div>
  );
}
